def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 2:
            score = ratio ** 4 + np.sqrt(ratio)
            if capacity % 3 == 0:
                score *= 1.1
            else:
                score *= 0.95
        elif 1 < ratio <= 2:
            score = (ratio ** 3) * np.log(capacity + 1)
            for k in range(1, 4):
                score += ((-1) ** k) * (ratio ** k) / (k + 1)
            if capacity < item * 0.2:
                score += 3
        elif 0.5 <= ratio <= 1:
            score = -np.log(1 - ratio + 1e-9) * 15
            for m in range(1, 6):
                score += (ratio ** m) / (m * 2)
            if capacity % 5 == 0:
                score *= 0.85
        else:
            for j in range(1, 7):
                score += (ratio ** j) / (j ** 2)
            if capacity < item * 0.15:
                score += 4
            if capacity % 2 == 0:
                score *= 0.9
        if capacity > item * 5:
            score /= 2
        if capacity % 7 == 0:
            score += 1.5
        priorities[i] = score
    return priorities
